MERGE INTO CONSULTAS FIN USING (SELECT '002423Sub_ResolucionDian' INFORME ,TO_CLOB(q'[ SELECT RESOLUCIONDIAN_CT.NUMERO, TO_CHAR(FECHAINICIAL, 'DD/MM/YYYY') FECHAINICIAL, TIPOCOMPROBANTE, 
CONSECUTIVOINI, CONSECUTIVOFIN
 FROM
   RESOLUCIONDIAN_CT
   INNER JOIN COMPROBANTE_CNT
   ON COMPROBANTE_CNT.COMPANIA         = RESOLUCIONDIAN_CT.COMPANIA   
    AND COMPROBANTE_CNT.TIPO           = RESOLUCIONDIAN_CT.TIPOCOMPROBANTE    
    AND COMPROBANTE_CNT.PREFIJODIAN    = RESOLUCIONDIAN_CT.PREFIJO
    AND COMPROBANTE_CNT.RESOLUCIONDIAN = RESOLUCIONDIAN_CT.NUMERO
   
WHERE
   RESOLUCIONDIAN_CT.COMPANIA = s$compania$s
   AND TIPOCOMPROBANTE ='s$tipoCpte$s' 
   AND COMPROBANTE_CNT.NUMERO BETWEEN  's$numeroPptoInicial$s' AND 's$numeroPptoFinal$s' ]') CONSULTA, 1 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, 'MROSERO' CREATED_BY, 'MROSERO' MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);
   
 MERGE INTO CONSULTAS_SUB FIN USING (SELECT '002420DSE_DocumentoSoporte' INFORME_PADRE, '002423Sub_ResolucionDian' INFORME_HIJO, 'PR_STRSQL_RESOLUCION' PARAMETRO ,'MROSERO' CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (FIN.INFORME_PADRE = INI.INFORME_PADRE AND INI.INFORME_HIJO = FIN.INFORME_HIJO)  WHEN MATCHED THEN  UPDATE SET FIN.PARAMETRO = INI.PARAMETRO , FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME_PADRE,INFORME_HIJO, PARAMETRO,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME_PADRE,INI.INFORME_HIJO, INI.PARAMETRO,INI.CREATED_BY,SYSDATE);
 
 MERGE INTO CONSULTAS_SUB FIN USING (SELECT '002449DocumentoSoporte' INFORME_PADRE, '002423Sub_ResolucionDian' INFORME_HIJO, 'PR_STRSQL_RESOLUCION' PARAMETRO ,'MROSERO' CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (FIN.INFORME_PADRE = INI.INFORME_PADRE AND INI.INFORME_HIJO = FIN.INFORME_HIJO)  WHEN MATCHED THEN  UPDATE SET FIN.PARAMETRO = INI.PARAMETRO , FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME_PADRE,INFORME_HIJO, PARAMETRO,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME_PADRE,INI.INFORME_HIJO, INI.PARAMETRO,INI.CREATED_BY,SYSDATE);

 MERGE INTO CONSULTAS_SUB FIN USING (SELECT '002601DocumentoSoporte' INFORME_PADRE, '002423Sub_ResolucionDian' INFORME_HIJO, 'PR_STRSQL_RESOLUCION' PARAMETRO ,'GROJAS' CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (FIN.INFORME_PADRE = INI.INFORME_PADRE AND INI.INFORME_HIJO = FIN.INFORME_HIJO)  WHEN MATCHED THEN  UPDATE SET FIN.PARAMETRO = INI.PARAMETRO , FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME_PADRE,INFORME_HIJO, PARAMETRO,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME_PADRE,INI.INFORME_HIJO, INI.PARAMETRO,INI.CREATED_BY,SYSDATE);
